mapper.insert:
INSERT INTO wannabe_dev.HOMPI_ALBUM(
  HOMPI_ID
, FOLDER_ID
, ALBUM_TITLE
, AVAIL_STATUS
, ALBUM_CONTENT
, ALBUM_IMG
, REMARKS
, INSERT_USER_ID
, INSERT_DT
, UPDATE_USER_ID
, UPDATE_DT
)
VALUES(
  #{hompiId}
, #{folderId}
, #{albumTitle}
, #{availStatus}
, #{albumContent}
, #{albumImage}
, NULL
, #{userId}
, current_timestamp()
, NULL
, NULL
);

mapper.select:
SELECT HOMPI_ID AS hompiId, ALBUM_ID AS albumId, ALBUM_IMG AS albumImage, ALBUM_TITLE AS albumTitle, ALBUM_CONTENT AS albumContent, AVAIL_STATUS AS availStatus, FOLDER_ID AS folderId, INSERT_USER_ID AS userId FROM HOMPI_ALBUM WHERE 1=1 AND HOMPI_ID= #{hompiId}
AND ALBUM_ID = #{albumId}
AND AVAIL_STATUS IN ('31', '32', '33')
AND AVAIL_STATUS IN ('32','33')
AND AVAIL_STATUS = '33'
ORDER BY INSERT_DT LIMIT 1

mapper.delete:
DELETE FROM HOMPI_ALBUM
 WHERE ALBUM_ID = #{albumId}
   AND HOMPI_ID = #{hompiId};
